# -*- coding: utf-8 -*-
import xbmc
import xbmcgui
import xbmcaddon
import threading

ADDON_PATH = xbmcaddon.Addon('plugin.video.elementum').getAddonInfo('path')

class BufferingDialog(xbmcgui.WindowXMLDialog):
    def onInit(self):
        xbmc.executebuiltin('Dialog.Close(busydialog)')
        xbmc.executebuiltin('Dialog.Close(busydialognocancel)')
        try:
            self.setFocusId(10)
        except:
            pass
        xbmcgui.Window(10000).setProperty('elem.buf.ready', 'true')
        xbmc.log('[plugin.video.elementum] BufferingDialog: onInit - ready', xbmc.LOGINFO)

    def onAction(self, action):
        action_id = action.getId()
        if action_id in [9, 10, 13, 92, 110, 216]:
            xbmc.log('[plugin.video.elementum] BufferingDialog: CANCELED (action %d)' % action_id, xbmc.LOGINFO)
            xbmcgui.Window(10000).setProperty('elem.buf.cancel', 'true')
            self.close()

dialog = BufferingDialog('resolver_window.xml', ADDON_PATH, 'Default', '720p')

def close_monitor():
    mon = xbmc.Monitor()
    win = xbmcgui.Window(10000)
    while not mon.abortRequested():
        if win.getProperty('elem.buf.close') == 'true':
            xbmc.log('[plugin.video.elementum] BufferingDialog: Close signal received', xbmc.LOGINFO)
            try:
                dialog.close()
            except:
                pass
            break
        if mon.waitForAbort(0.2):
            break

t = threading.Thread(target=close_monitor)
t.daemon = True
t.start()

dialog.doModal()
xbmc.log('[plugin.video.elementum] BufferingDialog: doModal ended', xbmc.LOGINFO)
xbmcgui.Window(10000).clearProperty('elem.buf.ready')
del dialog